SELECT * FROM ( SELECT ROWNUM RN, A.* FROM ( SELECT B.BOARD_ID AS boardId, B.MEMBER_ID AS memberId, B.TITLE AS title, B.REGION AS region, B.CATEGORY AS category, B.VIEW_CNT AS viewCnt, B.REG_DATE AS regDate, B.IMAGE_PATH AS imagePath, M.NAME AS memberName FROM TRV_BOARD B JOIN TRV_MEMBER M ON B.MEMBER_ID = M.MEMBER_ID
AND B.CATEGORY = #{category}
AND (B.TITLE LIKE '%' || #{keyword} || '%' OR B.CONTENT LIKE '%' || #{keyword} || '%')
ORDER BY B.BOARD_ID DESC ) A WHERE ROWNUM <= #{endRow} ) WHERE RN >= #{startRow}

SELECT COUNT(*) FROM TRV_BOARD B
AND B.CATEGORY = #{category}
AND (B.TITLE LIKE '%' || #{keyword} || '%' OR B.CONTENT LIKE '%' || #{keyword} || '%')

mapper.update:
UPDATE TRV_BOARD
SET TITLE = #{title},
    CONTENT = #{content},
    REGION = #{region},
    CATEGORY = #{category}

        , IMAGE_PATH = #{imagePath}

WHERE BOARD_ID = #{boardId}
